// Example: 1234567
const mgidWidgetIdFormatRegex = /^\d{7,20}$/;

export default function validateMgidWidgetIdFormat(value = '') {
  return Boolean(value.toLowerCase().match(mgidWidgetIdFormatRegex));
}
